import React from "react"

class Responsive extends React.Component {

  constructor(props) {
    super(props);
    this.state = {
      mobile: true,
      narrow: false,
      wide: false
    };

    this.running = false;

    this.updateView = this.updateView.bind(this);
  }

  componentDidMount() {
    window.addEventListener("resize", ev => {
      if (!this.running) {
        this.running = true;

        window.requestAnimationFrame(this.updateView);
      }
    });
    this.updateView();
  }

  componentWillUnmount() {
    window.removeEventListener("resize", this.updateView);
  }

  updateView() {
    let width = document.body.clientWidth;

    let { mobile, narrow, wide } = this.state;
    const { mobileWidth, wideWidth } = this.props;

    if ((mobile && width > mobileWidth) ||
      (narrow && !(width < wideWidth && width > mobileWidth)) ||
      (wide && width < wideWidth)) {
        this.setState({
          mobile: width <= mobileWidth,
          narrow: width < wideWidth && width > mobileWidth,
          wide: width >= wideWidth
        });
    }

    this.running = false;
  }

  render() {
    return (
      <React.Fragment>
        {
          React.Children.map(this.props.children,
          el => React.cloneElement(el, this.props.props(this.state)))
        }
      </React.Fragment>
    )
  }
}

export default Responsive



