import React from "react";

class BannerPreview extends React.Component {

  constructor(props) {
    super(props);

    this.state = {
      campaign: props.campaign,
      target: props.target,
      width: props.dim[0].width,
      height: props.dim[0].height
    }

    this.select = React.createRef();

    this.change = this.change.bind(this);
  }

  change() {
    let opt = this.select.current.selectedOptions[0];
    let w = opt.dataset.width;
    let h = opt.dataset.height;
    this.setState(Object.assign({},
      this.state,
      {
        width: w,
        height: h
      }
    ));
  }

  render() {
    let { width, height, campaign, target } = this.state;
    return (
      <React.Fragment>
        <iframe
          id="bannerPreview"
          src={`/banners/${campaign}_${width}x${height}_${target}/index.html`}
          width={width}
          height={height}
          frameborder="0"
        />
        <select onChange={this.change} ref={this.select}>
        {this.props.dim.map(({width, height}, idx) =>
        <option
          data-width={width}
          data-height={height}
          value={`${width}x${height}`}
          key={idx}
          >{`${width}x${height}`}</option>
        )}
      </select>
      </React.Fragment>
    )
  }
}

export default BannerPreview;



