import React from "react";

import "./styles.scss";

const Education = ({ school, degrees }) =>
<React.Fragment>
  <h3
    className="school"
    >{school}</h3>
  {
    degrees.map(({ degree, program, year }, idx, arr) =>
    <h4
      className={`degree ${idx === arr.length - 1 ? `last` : ``}`}
      >{degree} - {program} {year}</h4>
    )
  }
</React.Fragment>

export default Education;



